using BuildingBlocks.Charts; using BuildingBlocks.Export; using BuildingBlocks.Grids; using Expenses.Charts; using Expenses.Domain; using Expenses.Features; using Expenses.Persistence; using FluentAssertions; using Microsoft.EntityFrameworkCore; using Microsoft.VisualStudio.TestTools.UnitTesting;
namespace BuildingBlocks.Tests.Expenses; /** <summary>Expense vertical tests.</summary> */ [TestClass] public sealed class ExpensesVerticalTests
{/** <summary>Grid/export/chart flow.</summary> */ [TestMethod] public async Task GridExportChart_Works(){await using var db=CreateDb();db.Expenses.Add(Expense.Create("مواد",100,new DateOnly(2026,1,5),"أ",null).Value);db.Expenses.Add(Expense.Create("مواد",250,new DateOnly(2026,1,20),"ب",null).Value);db.Expenses.Add(Expense.Create("نقل",50,new DateOnly(2026,2,1),"ج",null).Value);await db.SaveChangesAsync();var grid=await new GetExpensesGridHandler(db).Handle(new(new GridQuery{Filters=[new("category",GridFilterOp.Eq,"مواد")],Sort=[new("amount",true)]}),default);grid.Value.Items.Select(x=>x.Amount).Should().Equal(250,100);new ExcelGridExporter().Export(grid.Value.Items,[new("Category","الفئة",GridFieldType.Text)],"المصروفات").Should().NotBeEmpty();var chart=await new ExpensesChartDataSource(db).ComputeAsync(new("date","amount",ChartAggregation.Sum,[]),default);chart.Points.Should().Contain(x=>x.Label=="2026-01"&&x.Value==350);}
private static ExpensesDbContext CreateDb()=>new(new DbContextOptionsBuilder<ExpensesDbContext>().UseInMemoryDatabase(Guid.NewGuid().ToString()).Options);}
